1	/**
2	 * Tool-Usage Observer — observation 寫入層
3	 *
4	 * 把 tool 使用落盤成結構化 JSONL（observations.jsonl），供未來的
5	 * instinct-evolve analyzer 萃取 skill。本檔是「唯一寫入收斂點」：負責
6	 * schema 組裝、脫敏、截斷、size cap、fail-silent，零業務邏輯外洩。
7	 *
8	 * 目前只實作 Tier B（rich）：DirectProvider tool-loop 在 executeToolCalls 內寫，
9	 * 含 args（脫敏）+ output（截斷）+ isError。
10	 *
11	 * fail-silent：寫入失敗只 console.error，絕不向上拋（不得中斷 tool loop / session）。
12	 */
13	import { appendFileSync, existsSync, mkdirSync, statSync } from "node:fs";
14	import { dirname, join } from "node:path";
15	import { config } from "./config.js";
16	
17	// ─── 常數 ────────────────────────────────────────────────────────────────
18	
19	/** precedingTools 滾動長度上限（避免長駐 session 無界增長）。 */
20	const MAX_RECENT = 8;
21	
22	/** observations.jsonl 體積上限；超過即安靜停寫。 */
23	const OBS_MAX_BYTES = 32 * 1024 * 1024;
24	
25	/** 單筆 rich output 的 hard cap。 */
26	const OBS_MAX_OUTPUT_CHARS = 8 * 1024;
27	
28	/** 脫敏：key 名命中即把值替為 [REDACTED]。 */
29	const SECRET_KEY_RE = /token|key|secret|password|authorization|auth/i;
30	
31	/** observations.jsonl 預設路徑（測試可用 BRIDGE_OBSERVATIONS_PATH 覆蓋）。 */
32	export const OBSERVATIONS_PATH = join(config.memoryDir, "observations.jsonl");
33	
34	// ─── 型別 ────────────────────────────────────────────────────────────────
35	
36	export interface Observation {
37	  ts: string;
38	  source: "rich";
39	  name: string;
40	  sessionId: string;
41	  chatId?: number;
42	  precedingTools: string[];
43	  /** rich — 經 redactArgs。 */
44	  args?: Record<string, unknown>;
45	  /** rich — 經截斷。 */
46	  output?: string;
47	  /** rich */
48	  isError?: boolean;
49	}
50	
51	export interface RichObservationInput {
52	  name: string;
53	  args: Record<string, unknown>;
54	  output: string;
55	  isError: boolean;
56	  sessionId: string;
57	  chatId?: number;
58	  precedingTools: string[];
59	}
60	
61	// ─── 內部工具 ─────────────────────────────────────────────────────────────
62	
63	/** 寫入路徑：測試覆蓋優先，否則用 config.memoryDir 下的預設檔。 */
64	function observationsPath(): string {
65	  return process.env.BRIDGE_OBSERVATIONS_PATH || OBSERVATIONS_PATH;
66	}
67	
68	/** redactArgs 遞迴深度上限（防 stack overflow / 病態巢狀）。 */
69	const MAX_REDACT_DEPTH = 4;
70	
71	/**
72	 * shell command 內嵌 secret 的 best-effort 清除。
73	 */
74	function scrubSecretsInText(s: string): string {
75	  return s
76	    .replace(/Bearer\s+\S+/gi, "Bearer [REDACTED]")
77	    .replace(/\b(api[_-]?key|key|token|secret|password)\s*=\s*\S+/gi, "$1=[REDACTED]");
78	}
79	
80	/** 單一值脫敏。 */
81	function redactValue(key: string | undefined, v: unknown, depth: number): unknown {
82	  if (key && SECRET_KEY_RE.test(key)) return "[REDACTED]";
83	  if (key === "command" && typeof v === "string") return scrubSecretsInText(v);
84	  if (depth >= MAX_REDACT_DEPTH) return v;
85	  if (Array.isArray(v)) return v.map((item) => redactValue(undefined, item, depth + 1));
86	  if (v && typeof v === "object") return redactObject(v as Record<string, unknown>, depth + 1);
87	  return v;
88	}
89	
90	function redactObject(obj: Record<string, unknown>, depth: number): Record<string, unknown> {
91	  const out: Record<string, unknown> = {};
92	  for (const [k, v] of Object.entries(obj)) {
93	    out[k] = redactValue(k, v, depth);
94	  }
95	  return out;
96	}
97	
98	/**
99	 * 脫敏 args（best-effort，export 供測試及 tool-hooks）。
100	 */
101	export function redactArgs(args: Record<string, unknown>): Record<string, unknown> {
102	  return redactObject(args, 0);
103	}
104	
105	function truncate(s: string, max: number): string {
106	  return s.length > max ? s.slice(0, max) + `\n...[truncated ${s.length - max} chars]` : s;
107	}
108	
109	/**
110	 * 唯一落盤點。fail-silent。
111	 */
112	function appendObservation(build: () => Observation): void {
113	  try {
114	    const obs = build();
115	    const target = observationsPath();
116	    // size cap：超過上限安靜停寫
