// Rebuild topic shards from the master facts log.
// Usage:
//   node scripts/rebuild-topic-shards.mjs                  # auto-detect user(s)
//   node scripts/rebuild-topic-shards.mjs --user 763055942
//   node scripts/rebuild-topic-shards.mjs --dry-run        # classify only, no writes
//
// Reads <MEMORY_DIR>/facts-<userId>.md and rewrites
// <MEMORY_DIR>/facts_Topic/<userId>/<topic>.md. Safe to run any time —
// the master log is never modified.
//
// Uses the compiled dist/ output so topic-rules + facts-store behave
// exactly like the running bridge. Run `npm run build` first if dist is
// stale.

import { readdirSync, existsSync } from "node:fs";
import path from "node:path";
import { argv } from "node:process";

// We intentionally import from dist so a single source of truth (the
// built topic-rules + facts-store) is used. The scripts dir is not
// compiled.
const { rebuildShards, resolveMemoryDir, userShardDir } = await import(
  "../dist/facts-store.js"
);

function parseArgs() {
  const out = { user: null, dryRun: false };
  const args = argv.slice(2);
  for (let i = 0; i < args.length; i++) {
    const a = args[i];
    if (a === "--user" || a === "-u") {
      out.user = args[++i];
    } else if (a === "--dry-run") {
      out.dryRun = true;
    } else if (a === "--help" || a === "-h") {
      console.log(
        "usage: rebuild-topic-shards.mjs [--user <id>] [--dry-run]"
      );
      process.exit(0);
    } else {
      console.error(`unknown arg: ${a}`);
      process.exit(2);
    }
  }
  return out;
}

function discoverUsers(memDir) {
  if (!existsSync(memDir)) return [];
  const users = [];
  for (const name of readdirSync(memDir)) {
    // facts-<digits>.md
    const m = /^facts-(\d+)\.md$/i.exec(name);
    if (m) users.push(m[1]);
  }
  return users;
}

const { user, dryRun } = parseArgs();
const memDir = resolveMemoryDir();
const users = user ? [user] : discoverUsers(memDir);

if (users.length === 0) {
  console.error(`no facts-<userId>.md found in ${memDir}`);
  process.exit(1);
}

console.log(`memory dir: ${memDir}`);
console.log(`users: ${users.join(", ")}`);
console.log(`mode: ${dryRun ? "dry-run (classify only)" : "rewrite"}`);
console.log("");

let grandTotal = 0;
for (const uid of users) {
  const shardDir = userShardDir(uid);
  if (dryRun) {
    // Re-use the same classification path but don't touch disk. Easiest
    // is to import classifyFact + read the master log directly.
    const { classifyFact } = await import("../dist/topic-rules.js");
    const { readFileSync } = await import("node:fs");
    const master = path.join(memDir, `facts-${uid}.md`);
    let raw = "";
    try {
      raw = readFileSync(master, "utf8");
    } catch {
      console.log(`[${uid}] (no master log at ${master})`);
      continue;
    }
    const lines = raw
      .split(/\r?\n/)
      .map((l) => l.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim())
      .filter(Boolean);
    const per = {};
    for (const t of lines) {
      const topic = classifyFact(t) || "misc";
      per[topic] = (per[topic] ?? 0) + 1;
    }
    const sorted = Object.entries(per).sort((a, b) => b[1] - a[1]);
    console.log(`[${uid}] would write ${lines.length} facts into ${shardDir}:`);
    for (const [t, n] of sorted) console.log(`  - ${t}.md  (${n})`);
    grandTotal += lines.length;
    continue;
  }

  const res = rebuildShards(uid);
  const sorted = Object.entries(res.perTopic).sort((a, b) => b[1] - a[1]);
  console.log(`[${uid}] wrote ${res.total} facts → ${res.shardDir}`);
  for (const [t, n] of sorted) console.log(`  - ${t}.md  (${n})`);
  grandTotal += res.total;
}

console.log("");
console.log(`done. total facts ${dryRun ? "classified" : "written"}: ${grandTotal}`);

