/**
 * Pin model and/or effort on the freshly-created session via the ACP
 * `session/set_config_option` request (read from opts.acpModel/acpEffort).
 *
 * Best-effort: any failure (adapter doesn't support the method, invalid
 * value, dead stream) is logged to stderr and swallowed so it can never
 * abort session startup. No-op when neither option is configured, which is
 * the case for every ephemeral call site (scheduler / specialist /
 * daily-intel / session-extract) — only the main interactive session wires
 * these through, so their behaviour is unchanged.
 *
 * Model is applied before effort because the adapter rebuilds the effort
 * option list from the selected model (effort levels are model-specific).
 */
private async applyModelEffort(): Promise<void> {
  const model = (this.opts.acpModel ?? "").trim();
  const effort = (this.opts.acpEffort ?? "").trim();
  if (!model && !effort) return;
  if (!this.sessionId) return;

  const set = async (configId: string, value: string) => {
    try {
      await this.call("session/set_config_option", {
        sessionId: this.sessionId,
        configId,
        value,
      });
      this.emit("stderr", `[acp] pinned ${configId}=${value}\n`);
    } catch (err) {
      const msg = (err as Error).message ?? String(err);
      this.emit(
        "stderr",
        `[acp] set ${configId}=${value} not applied (ignored): ${msg}\n`,
      );
    }
  };

